      const result = generateSearchQueries(['authentication', 'login', 'logout', 'jwt']);
      expect(result.length).toBeLessThanOrEqual(2);
      expect(result[0]).toBe('authentication');
    });

    it('should combine first two keywords for multi-query', () => {
