          with_payload: true
        });

        const embeddedResults = await embeddedClient.search(COLLECTION_NAME, {
          vector: { name: VECTOR_NAME, vector: embedding },
          limit: 3,
          with_payload: true
        });

        // I risultati devono essere equivalenti (stesso numero di punti)
        expect(embeddedResults.length).toBe(dockerResults.length);

        // I payload devono essere identici
        for (let i = 0; i < Math.min(dockerResults.length, embeddedResults.length); i++) {
          expect(embeddedResults[i].payload).toEqual(dockerResults[i].payload);
        }

        console.error('✅ Query results are identical between Docker and embedded');
      } finally {
        try {
          await embeddedClient.deleteCollection(COLLECTION_NAME);
        } catch (err) {
          // Ignore
        }
      }
    });

    it('deve mantenere integrità dei dati dopo "migrazione"', async () => {
      if (!collectionExists) {
        console.error('⚠️  Skipping integrity test - Qdrant Docker not available');
        return;
      }

      const embeddedUrl = `file://${TEST_STORAGE_PATH}`;
      embeddedClient = new QdrantClient({ url: embeddedUrl });

      try {
        // Crea collection e inserisci dati
        await embeddedClient.createCollection(COLLECTION_NAME, {
          vectors: { [VECTOR_NAME]: { size: 1024, distance: 'Cosine' } }
        });

        const originalPoints = createTestPoints();
        await embeddedClient.upsert(COLLECTION_NAME, { points: originalPoints });

        // Simula "lettura" dei dati dopo migrazione
