          expect(point.payload.source).toBeDefined();
          expect(point.payload.summary).toBeDefined();
        });

        // 3. I payload sono coerenti con i dati originali
        const originalIds = originalPoints.map(p => String(p.id));
        const foundIds = scrollResult.map(p => String(p.id));
        expect(new Set(foundIds)).toEqual(new Set(originalIds));

        console.error('✅ Data integrity maintained after migration');
      } finally {
        try {
          await embeddedClient.deleteCollection(COLLECTION_NAME);
        } catch (err) {
          // Ignore
        }
      }
    });
  });

  describe('Test standalone embedded', () => {
    it('deve creare e popolare collection embedded senza Docker', async () => {
      if (!embeddedCollectionCreated) {
        console.error('⚠️  Skipping standalone test - Embedded collection not created');
        return;
      }

      const embeddedUrl = `file://${TEST_STORAGE_PATH}`;
      const standaloneClient = new QdrantClient({ url: embeddedUrl });

      try {
        // Ricrea collection per test standalone
        await standaloneClient.createCollection(COLLECTION_NAME, {
          vectors: { [VECTOR_NAME]: { size: 1024, distance: 'Cosine' } }
        });

        const points = createTestPoints();
        await standaloneClient.upsert(COLLECTION_NAME, { points });

        // Verifica che i dati siano stati salvati correttamente
