        expect(scrollResult.length).toBe(points.length);

        // Verifica che ogni punto abbia payload completa
        scrollResult.forEach(point => {
          expect(point.payload.type).toBeDefined();
          expect(point.payload.source).toBeDefined();
          expect(point.payload.summary).toBeDefined();
