  });

  describe('Test di compatibilità schema', () => {
    it('deve supportare gli stessi tipi di payload su Docker e embedded', async () => {
      if (!collectionExists && !embeddedCollectionCreated) {
        console.error('⚠️  Skipping schema compatibility test - No Qdrant available');
        return;
      }

      const embeddedUrl = `file://${TEST_STORAGE_PATH}`;
      embeddedClient = new QdrantClient({ url: embeddedUrl });

      try {
        await embeddedClient.createCollection(COLLECTION_NAME, {
          vectors: { [VECTOR_NAME]: { size: 1024, distance: 'Cosine' } }
        });

        // Test payload con vari tipi di dati (simila a quelli reali)
        const complexPayload = {
          type: 'doc',
          source: '.gsd/milestones/M001/slices/S02/S02-PLAN.md',
          summary: 'Slice S02 - Testing e validazione',
          content: 'Questo è un payload complesso con molti campi',
          project_id: 'test-project-id',
          tags: ['testing', 'validation', 'slice'],
          metadata: {
            author: 'test-user',
            created: new Date().toISOString(),
            version: 1
          },
          numeric_field: 42,
          boolean_field: true
        };

        const point = {
          id: 'complex_payload_test',
          payload: complexPayload,
          vector: generatePlaceholderEmbedding('complex payload test')
        };

        await embeddedClient.upsert(COLLECTION_NAME, { points: [point] });

        // Recupera e verifica
        const result = await embeddedClient.retrieve(COLLECTION_NAME, ['complex_payload_test'], {
          with_payload: true
        });

        expect(result.length).toBe(1);
        expect(result[0].payload).toEqual(complexPayload);

        console.error('✅ Complex payloads are fully compatible');
      } finally {
        try {
          await embeddedClient.deleteCollection(COLLECTION_NAME);
        } catch (err) {
          // Ignore
        }
      }
    });
  });
